<style scoped>
.search-mode-toggle {
  display: flex;
  gap: 10px;
}

.search-mode-toggle button {
  background-color: #57CC99; /* 默认背景色 */
  color: #1E2C34; /* 默认字体颜色 */
  border: none;
  padding: 8px 16px;
  cursor: pointer;
  border-radius: 4px;
  font-size: 14px;
  transition: all 0.3s ease;
}

/* 鼠标悬停时 */
.search-mode-toggle button:hover {
  background-color: #13ADA5; /* 背景颜色变深 */
}

/* 选中状态（active） */
.search-mode-toggle button.active {
  background-color: #13ADA5; /* 选中时背景变浅 */
  font-weight: bold;
}
</style>
<template>

  <div class="search-container">
    <h1>方言词汇搜索系统</h1>

    <div class="search-mode-toggle">
      <button
        :class="{ active: searchMode === 'basic' }"
        @click="searchMode = 'basic'">基本搜索</button>
      <button
        :class="{ active: searchMode === 'advanced' }"
        @click="searchMode = 'advanced'">高级搜索</button>
    </div>

    <!-- 基本搜索 -->
    <div v-if="searchMode === 'basic'" class="search-form basic">
      <input
        v-model="basicSearchTerm"
        @keyup.enter="performBasicSearch"
        placeholder="请输入词汇...">
      <button @click="performBasicSearch">搜索</button>
    </div>

    <!-- 高级搜索 -->
    <div v-else class="search-form advanced">
      <div class="form-group">
        <label>词汇:</label>
        <input v-model="advancedSearch.word" placeholder="请输入词汇">
      </div>
      <div class="form-group">
        <label>老派词汇:</label>
        <input v-model="advancedSearch.oldDialect" placeholder="请输入老派词汇">
      </div>
      <div class="form-group">
        <label>新派词汇:</label>
        <input v-model="advancedSearch.newDialect" placeholder="请输入新派词汇">
      </div>
      <button @click="performAdvancedSearch">高级搜索</button>
    </div>

    <!-- 搜索结果 -->
    <div class="search-results">
      <h2>搜索结果 ({{ searchResults.length }})</h2>
      <table v-if="searchResults.length > 0">
        <thead>
          <tr>
            <th>编号</th>
            <th>词汇</th>
            <th>老派词汇</th>
            <th>老派语音</th>
            <th>新派词汇</th>
            <th>新派语音</th>
          </tr>
        </thead>
        <tbody>
          <tr v-for="item in searchResults" :key="item.id">
            <td>{{ item.code }}</td>
            <td>{{ item.word }}</td>
            <td>{{ item.old_dialect_word }}</td>
            <td>
              <audio-player
                v-if="item.old_dialect_audio"
                :src="item.old_dialect_audio"/>
              <span v-else>无音频</span>
            </td>
            <td>{{ item.new_dialect_word }}</td>
            <td>
              <audio-player
                v-if="item.new_dialect_audio"
                :src="item.new_dialect_audio" />
              <span v-else>无音频</span>
            </td>
          </tr>
        </tbody>
      </table>
      <div v-else class="no-results">
        <p>没有找到匹配的结果</p>
      </div>
    </div>
  </div>
</template>

<script>
import AudioPlayer from '@/components/AudioPlayer.vue';
import api from '@/services/api';

export default {
  components: {
    AudioPlayer
  },
  data() {
    return {
      searchMode: 'basic',
      basicSearchTerm: '',
      advancedSearch: {
        word: '',
        oldDialect: '',
        newDialect: ''
      },
      searchResults: [],
      apiBaseUrl: process.env.VUE_APP_API_URL || 'http://localhost:8000'
    };
  },
  methods: {
    async performBasicSearch() {
      if (!this.basicSearchTerm.trim()) return;

      try {
        this.isLoading = true;
        const response = await api.get('/dialect-words/', {
          params: { search: this.basicSearchTerm }
        });
        this.searchResults = response.data.results || response.data;
      } catch (error) {
        console.error('搜索失败:', error);
        this.searchResults = [];
      } finally {
        this.isLoading = false;
      }
    },
    async performAdvancedSearch() {
      try {
        this.isLoading = true;
        const params = {};
        if (this.advancedSearch.word) params.word = this.advancedSearch.word;
        if (this.advancedSearch.oldDialect) params.old_dialect = this.advancedSearch.oldDialect;
        if (this.advancedSearch.newDialect) params.new_dialect = this.advancedSearch.newDialect;

        const response = await api.get('/dialect-words/', { params });
        this.searchResults = response.data.results || response.data;
      } catch (error) {
        console.error('高级搜索失败:', error);
        this.searchResults = [];
      } finally {
        this.isLoading = false;
      }
    }
  }
};
</script>

<style scoped>
.search-container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 20px;
}



.search-form {
  margin-bottom: 30px;
  padding: 20px;
  background-color: #f9f9f9;
  border-radius: 5px;
}

.search-form.basic {
  display: flex;
}

.search-form.basic input {
  flex: 1;
  padding: 10px;
  margin-right: 10px;
}

.form-group {
  margin-bottom: 15px;
  display: flex;
  align-items: center;
}

.form-group label {
  width: 100px;
}

.form-group input {
  flex: 1;
  padding: 10px;
}

button {
  padding: 10px 20px;
  background-color: #4a90e2;
  color: white;
  border: none;
  border-radius: 3px;
  cursor: pointer;
}

table {
  width: 100%;
  border-collapse: collapse;
}

th, td {
  padding: 12px;
  text-align: left;
  border-bottom: 1px solid #ddd;
}

th {
  background-color: #f2f2f2;
}

.no-results {
  text-align: center;
  padding: 30px;
  background-color: #f9f9f9;
  border-radius: 5px;
}
</style>