<template>
  <div class="data-container">
    <h1>词汇数据库</h1>

    <div class="filters">
      <div class="filter-group">
        <label>每页显示:</label>
        <select v-model="pageSize" @change="loadData">
          <option :value="10">10</option>
          <option :value="20">20</option>
          <option :value="50">50</option>
          <option :value="100">100</option>
        </select>
      </div>
    </div>

    <div v-if="isLoading" class="loading">
      <p>数据加载中...</p>
    </div>

    <table v-else>
      <thead>
        <tr>
          <th>编号</th>
          <th>词汇</th>
          <th>老派词汇</th>
          <th>老派语音</th>
          <th>新派词汇</th>
          <th>新派语音</th>
        </tr>
      </thead>
      <tbody>
        <tr v-for="item in dataList" :key="item.id">
          <td>{{ item.code }}</td>
          <td>{{ item.word }}</td>
          <td>{{ item.old_dialect_word }}</td>
          <td>
            <audio-player
              v-if="item.old_dialect_audio"
              :src="item.old_dialect_audio" />
            <span v-else>无音频</span>
          </td>
          <td>{{ item.new_dialect_word }}</td>
          <td>
            <audio-player
              v-if="item.new_dialect_audio"
              :src="item.new_dialect_audio" />
            <span v-else>无音频</span>
          </td>
        </tr>
      </tbody>
    </table>

    <div class="pagination">
      <button
        @click="prevPage"
        :disabled="currentPage === 1">
        上一页
      </button>
      <span class="page-info">{{ currentPage }} / {{ totalPages || 1 }}</span>
      <button
        @click="nextPage"
        :disabled="currentPage >= totalPages">
        下一页
      </button>
    </div>
  </div>
</template>

<script>
import AudioPlayer from '@/components/AudioPlayer.vue';
import api from '@/services/api';

export default {
  components: {
    AudioPlayer
  },
  data() {
    return {
      dataList: [],
      currentPage: 1,
      pageSize: 20,
      totalItems: 0,
      isLoading: false,
      apiBaseUrl: process.env.VUE_APP_API_URL || 'http://localhost:8000'
    };
  },
  computed: {
    totalPages() {
      return Math.ceil(this.totalItems / this.pageSize) || 1;
    }
  },
  mounted() {
    this.loadData();
  },
  methods: {
    async loadData() {
      try {
        this.isLoading = true;
        const response = await api.get('dialect-words/', {
          params: {
            page: this.currentPage,
            page_size: this.pageSize
          }
        });

        this.dataList = response.data.results || response.data;
        this.totalItems = response.data.count || this.dataList.length;
      } catch (error) {
        console.error('加载数据失败:', error);
        this.dataList = [];
      } finally {
        this.isLoading = false;
      }
    },
    prevPage() {
      if (this.currentPage > 1) {
        this.currentPage -= 1;
        this.loadData();
      }
    },
    nextPage() {
      if (this.currentPage < this.totalPages) {
        this.currentPage += 1;
        this.loadData();
      }
    }
  }
};
</script>

<style scoped>
.data-container {
  max-width: 1200px;
  margin: 0 auto;
  padding: 20px;
}

.filters {
  margin-bottom: 20px;
  display: flex;
  justify-content: flex-end;
}

.filter-group {
  margin-left: 15px;
  display: flex;
  align-items: center;
}

.filter-group label {
  margin-right: 8px;
}

.loading {
  text-align: center;
  padding: 50px;
  background-color: #f9f9f9;
  border-radius: 5px;
}

table {
  width: 100%;
  border-collapse: collapse;
  margin-bottom: 30px;
}

th, td {
  padding: 12px;
  text-align: left;
  border-bottom: 1px solid #ddd;
}

th {
  background-color: #f2f2f2;
}

.pagination {
  display: flex;
  justify-content: center;
  align-items: center;
  margin-top: 20px;
}

.pagination button {
  padding: 8px 15px;
  background-color: #4a90e2;
  color: white;
  border: none;
  border-radius: 3px;
  cursor: pointer;
  margin: 0 10px;
}

.pagination button:disabled {
  background-color: #ccc;
  cursor: not-allowed;
}

.page-info {
  font-size: 14px;
}
</style>