<template>
  <div class="import-container">
    <h1>导入数据</h1>

    <div class="form-container">
      <div class="info-box">
        <h3>导入说明</h3>
        <p>1. 请上传正确格式的Excel文件。文件应包含以下列：编号、词汇、老派词汇、新派词汇</p>
        <p>2. 系统会自动查找与词条对应的MP3文件。文件命名规则为：<code>[编号] [类型] [词汇].mp3</code></p>
        <p>3. 例如：<code>0001 老派.mp3</code> 和 <code>0001 新派.mp3</code></p>
      </div>

      <div class="form-group">
        <label>上传Excel文件:</label>
        <input
          type="file"
          @change="handleFileChange"
          accept=".xlsx,.xls"
        >
      </div>

      <div class="buttons">
        <button
          @click="uploadFile"
          :disabled="!selectedFile || isUploading"
          class="primary-button"
        >
          {{ isUploading ? '上传中...' : '上传并导入' }}
        </button>
      </div>

      <div v-if="uploadResult" class="result-message" :class="{ success: uploadResult.success }">
        <h3>{{ uploadResult.success ? '导入成功' : '导入失败' }}</h3>
        <p>{{ uploadResult.message }}</p>

        <div v-if="uploadResult.errors && uploadResult.errors.length > 0" class="error-details">
          <h4>错误详情:</h4>
          <ul>
            <li v-for="(error, index) in uploadResult.errors" :key="index">
              编号 {{ error.code }} ({{ error.word }}): {{ error.error }}
            </li>
          </ul>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import api from '@/services/api';

export default {
  data() {
    return {
      selectedFile: null,
      isUploading: false,
      uploadResult: null
    };
  },
  methods: {
    handleFileChange(event) {
      this.selectedFile = event.target.files[0];
      this.uploadResult = null;
    },
    async uploadFile() {
      if (!this.selectedFile) return;

      this.isUploading = true;
      this.uploadResult = null;

      const formData = new FormData();
      formData.append('excel_file', this.selectedFile);

      try {
        const response = await api.post('import-excel/', formData, {
          headers: {
            'Content-Type': 'multipart/form-data'
          }
        });

        this.uploadResult = response.data;
      } catch (error) {
        console.error('上传失败:', error);
        this.uploadResult = {
          success: false,
          message: '上传失败: ' + (error.response?.data?.message || error.message)
        };
      } finally {
        this.isUploading = false;
      }
    }
  }
};
</script>

<style scoped>
.import-container {
  max-width: 800px;
  margin: 0 auto;
  padding: 20px;
}

.form-container {
  background-color: #f9f9f9;
  padding: 30px;
  border-radius: 5px;
}

.info-box {
  background-color: #e8f4ff;
  padding: 15px;
  border-radius: 5px;
  margin-bottom: 25px;
  border-left: 4px solid #4a90e2;
}

.info-box p {
  margin: 8px 0;
}

.form-group {
  margin-bottom: 20px;
}

.form-group label {
  display: block;
  margin-bottom: 8px;
  font-weight: bold;
}

.buttons {
  margin-top: 20px;
}

.primary-button {
  padding: 12px 25px;
  background-color: #4a90e2;
  color: white;
  border: none;
  border-radius: 3px;
  cursor: pointer;
  font-size: 16px;
}

.primary-button:disabled {
  background-color: #ccc;
  cursor: not-allowed;
}

.result-message {
  margin-top: 30px;
  padding: 15px;
  border-radius: 5px;
  background-color: #ffebee;
  border: 1px solid #ffcdd2;
}

.result-message.success {
  background-color: #e8f5e9;
  border: 1px solid #c8e6c9;
}

.error-details {
  margin-top: 15px;
}

.error-details ul {
  padding-left: 20px;
}

.error-details li {
  margin-bottom: 5px;
}

code {
  background-color: #f0f0f0;
  padding: 2px 5px;
  border-radius: 3px;
  font-family: monospace;
}
</style>